// --- 1. CONFIGURAÇÃO INICIAL ---
const nodeUsuario = $('Converter Endereço em Latitude/Longitude').first().json.results[0].geometry.location;
const userLat = nodeUsuario.lat;
const userLng = nodeUsuario.lng;

// LÊ A LISTA DE EXCLUÍDOS
let inputExcluidos = $('Organiza o input do AI Agent').first().json.aeroportos_excluidos || [];
if (typeof inputExcluidos === 'string') {
    inputExcluidos = inputExcluidos.split(',').map(s => s.trim());
}
const listaExcluidos = inputExcluidos.map(item => item.toUpperCase());

// --- 2. FUNÇÃO HAVERSINE ---
function getDistanceFromLatLonInKm(lat1, lon1, lat2, lon2) {
  const R = 6371; 
  const dLat = deg2rad(lat2 - lat1);
  const dLon = deg2rad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(deg2rad(lat1)) * Math.cos(deg2rad(lat2)) * Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return parseFloat((R * c).toFixed(2));
}
function deg2rad(deg) { return deg * (Math.PI/180); }

// --- 3. TABELA FIXA DE HUBS ---
const HUBS_BRASIL = [
    { iata: "GRU", nome: "Guarulhos (SP)", lat: -23.4323, lng: -46.4695, tipo: "Global" },
    { iata: "VCP", nome: "Viracopos (Campinas)", lat: -23.0074, lng: -47.1345, tipo: "Global" },
    { iata: "GIG", nome: "Galeão (RJ)", lat: -22.8093, lng: -43.2506, tipo: "Global" },
    { iata: "CNF", nome: "Confins (BH)", lat: -19.6244, lng: -43.9719, tipo: "Global" },
    { iata: "BSB", nome: "Brasília (DF)", lat: -15.8696, lng: -47.9208, tipo: "Global" },
    { iata: "REC", nome: "Recife (PE)", lat: -8.1259, lng: -34.9240, tipo: "Global/LatAm" },
    { iata: "SSA", nome: "Salvador (BA)", lat: -12.9069, lng: -38.3315, tipo: "Global/LatAm" },
    { iata: "FOR", nome: "Fortaleza (CE)", lat: -3.7757, lng: -38.5326, tipo: "Global/LatAm" },
    { iata: "POA", nome: "Porto Alegre (RS)", lat: -29.9934, lng: -51.1711, tipo: "LatAm" },
    { iata: "CWB", nome: "Curitiba (PR)", lat: -25.5327, lng: -49.1758, tipo: "LatAm" },
    { iata: "FLN", nome: "Florianópolis (SC)", lat: -27.6701, lng: -48.5459, tipo: "LatAm" },
    { iata: "MAO", nome: "Manaus (AM)", lat: -3.0360, lng: -60.0520, tipo: "LatAm" },
    { iata: "BEL", nome: "Belém (PA)", lat: -1.3792, lng: -48.4766, tipo: "LatAm" }
];

// --- 4. PROCESSAR HUBS ---
let hubsCalculados = HUBS_BRASIL.map(hub => {
    return {
        nome: hub.nome,
        iata: hub.iata,
        tipo: hub.tipo,
        distancia_km: getDistanceFromLatLonInKm(userLat, userLng, hub.lat, hub.lng)
    };
});

// Filtro de Exclusão
hubsCalculados = hubsCalculados.filter(hub => !listaExcluidos.includes(hub.iata));

// Ordenação
hubsCalculados.sort((a, b) => a.distancia_km - b.distancia_km);
const topHubs = hubsCalculados.slice(0, 3);

// --- 4.5 LÓGICA DOS 80KM (NOVO) ---
// Verifica se o Hub mais próximo é Global/Internacional E está a menos de 80km
let hubGlobalPerto = null;
const hubMaisPerto = hubsCalculados[0]; // Como já está ordenado, o índice 0 é o mais perto

if (hubMaisPerto && hubMaisPerto.distancia_km <= 80 && hubMaisPerto.tipo.includes("Global")) {
    hubGlobalPerto = hubMaisPerto;
}

// --- 5. PROCESSAR LOCAIS GOOGLE ---
const resultados = items[0].json.results || [];
const palavrasProibidas = ["heliponto", "heliporto", "hangar", "aeroclube", "pista", "serviços", "taxi", "táxi", "pipas", "base aérea", "estacionamento", "park", "escola"];
const RELEVANCIA_MINIMA_TOP = 2000; 

let locaisGoogle = resultados.map(local => {
    const dist = getDistanceFromLatLonInKm(userLat, userLng, local.geometry.location.lat, local.geometry.location.lng);
    return {
        nome: local.name,
        endereco: local.vicinity,
        rating: local.user_ratings_total || 0,
        distancia_km: parseFloat(dist.toFixed(2)),
        place_id: local.place_id,
        origem_dado: "Google Maps (Local)"
    };
});

// Filtros Locais
locaisGoogle = locaisGoogle.filter(c => {
    const nomeLower = c.nome.toLowerCase();
    if (palavrasProibidas.some(p => nomeLower.includes(p))) return false;
    if (c.rating < 50) return false; 
    if (listaExcluidos.some(exc => c.nome.toUpperCase().includes(exc))) return false;
    return true;
});

locaisGoogle.sort((a, b) => {
    const aIsBig = a.rating >= RELEVANCIA_MINIMA_TOP;
    const bIsBig = b.rating >= RELEVANCIA_MINIMA_TOP;
    if (aIsBig && bIsBig) return a.distancia_km - b.distancia_km; 
    if (aIsBig && !bIsBig) return -1;
    if (!aIsBig && bIsBig) return 1;
    return b.rating - a.rating; 
});

const finalistasLocais = locaisGoogle.slice(0, 5);

// --- 6. RETORNO ---
const encontrouAlgo = finalistasLocais.length > 0 || topHubs.length > 0;

return [{
    json: {
        encontrado: encontrouAlgo,
        aeroportos_locais: finalistasLocais,
        hubs_calculados: topHubs,
        // Variável NOVA para o Prompt
        hub_global_prioritario: hubGlobalPerto, 
        debug_excluidos: listaExcluidos
    }
}];

// Pega o texto completo retornado pelo Agente
const textoCompleto = items[0].json.output;

let jsonFinal = {};

try {
  // ESTRATÉGIA 1: Tentar extrair o conteúdo de dentro dos blocos de código Markdown (```json ... ```)
  // A regex procura por ``` (opcionalmente seguido de json), pega tudo no meio, e termina com ```
  const regexCodeBlock = /```(?:json)?\s*([\s\S]*?)\s*```/i;
  const match = textoCompleto.match(regexCodeBlock);

  let stringJson = "";

  if (match && match[1]) {
    // Se encontrou o bloco de código, usa o conteúdo dele
    stringJson = match[1];
  } else {
    // ESTRATÉGIA 2 (Fallback): Se o agente esqueceu os ```, tenta achar o primeiro '{' e o último '}'
    const inicio = textoCompleto.indexOf('{');
    const fim = textoCompleto.lastIndexOf('}');

    if (inicio !== -1 && fim !== -1) {
      stringJson = textoCompleto.substring(inicio, fim + 1);
    } else {
      throw new Error("Nenhum objeto JSON encontrado no texto.");
    }
  }

  // Converte a string limpa em um Objeto JavaScript real
  jsonFinal = JSON.parse(stringJson);

} catch (error) {
  // Caso algo dê errado (ex: o agente não retornou JSON), devolve o erro e o texto original para debug
  jsonFinal = {
    encontrado: false,
    erro_parse: error.message,
    texto_bruto: textoCompleto
  };
}

// Retorna o JSON limpo para o próximo node usar (ex: $json.nome_aeroporto)
return [{
  json: jsonFinal
}];

