// --- 1. CONFIGURAÇÃO INICIAL ---
// Pega a localização do usuário do node anterior (Garanta que o nome do node está certo)
const nodeUsuario = $('Converter Endereço em Latitude/Longitude').first().json.results[0].geometry.location;
const userLat = nodeUsuario.lat;
const userLng = nodeUsuario.lng;

// LÊ A LISTA DE EXCLUÍDOS (Vindo do node que organiza o input)
// Procura por 'opcoes_excluidas' (novo padrão) ou 'aeroportos_excluidos' (fallback)
let rawExcluidos = $('Organiza o input do AI Agent').first().json.opcoes_excluidas || [];

// Garante que é array
let listaExcluidos = [];
if (typeof rawExcluidos === 'string') {
    listaExcluidos = rawExcluidos.split(',').map(s => s.trim().toUpperCase());
} else if (Array.isArray(rawExcluidos)) {
    listaExcluidos = rawExcluidos.map(s => s.toString().toUpperCase());
}

// --- 2. FUNÇÃO HAVERSINE (Cálculo de Distância) ---
function getDistanceFromLatLonInKm(lat1, lon1, lat2, lon2) {
  const R = 6371; 
  const dLat = deg2rad(lat2 - lat1);
  const dLon = deg2rad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(deg2rad(lat1)) * Math.cos(deg2rad(lat2)) * Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return parseFloat((R * c).toFixed(2));
}
function deg2rad(deg) { return deg * (Math.PI/180); }

// --- 3. PROCESSAMENTO E FILTRAGEM (Lógica de Rodoviária) ---
const resultados = items[0].json.results || [];

// PALAVRAS QUE INDICAM QUE O LOCAL NÃO É UMA RODOVIÁRIA REAL
const palavrasProibidas = [
    "ponto de", "parada", "bus stop", "ponto final", // Pontos de rua
    "agência", "guichê", "loja", "ticket", "passagens", // Lojas que vendem bilhete mas não embarcam
    "encomendas", "cargas", "logística", // Terminais de carga
    "urbano", "circular", "metropolitano", // Terminais locais (não viagem)
    "borracharia", "lanchonete", "hotel" // Lixo do Google Maps
];

// Mínimo de avaliações para considerar que é um Terminal Relevante
// Rodoviárias geralmente têm muitas avaliações. Pontos de rua têm poucas.
const RATING_COUNT_MINIMO = 30; 

let rodoviariasGoogle = resultados.map(local => {
    const dist = getDistanceFromLatLonInKm(userLat, userLng, local.geometry.location.lat, local.geometry.location.lng);
    return {
        nome: local.name,
        endereco: local.vicinity || local.formatted_address,
        rating_count: local.user_ratings_total || 0,
        nota: local.rating || 0,
        distancia_km: parseFloat(dist.toFixed(2)),
        place_id: local.place_id,
        types: local.types || [],
        origem_dado: "Google Maps (Rodoviária)"
    };
});

// --- 4. APLICANDO OS FILTROS ---
rodoviariasGoogle = rodoviariasGoogle.filter(r => {
    const nomeLower = r.nome.toLowerCase();

    // Filtro 1: Palavras proibidas (Remove "Ponto de Onibus", "Agencia", etc)
    if (palavrasProibidas.some(p => nomeLower.includes(p))) return false;

    // Filtro 2: Rating Count (Remove locais fantasmas ou irrelevantes)
    // Se tiver menos que X avaliações, provavelmente não é a rodoviária principal
    if (r.rating_count < RATING_COUNT_MINIMO) return false; 

    // Filtro 3: Exclusão do usuário (Se ele já disse "Não quero a Rodoviária X")
    if (listaExcluidos.some(exc => r.nome.toUpperCase().includes(exc))) return false;

    // Filtro 4: Tipo Obrigatório (Segurança extra)
    // O local DEVE ter tag 'bus_station' ou 'transit_station'
    if (!r.types.includes('bus_station') && !r.types.includes('transit_station')) return false;

    return true;
});

// --- 5. ORDENAÇÃO INTELIGENTE ---
rodoviariasGoogle.sort((a, b) => {
    // Para rodoviárias, distância é o rei.
    // Mas se a diferença for pequena (< 5km), prioriza a que tem mais avaliações (provável terminal principal)

    const diffDistancia = Math.abs(a.distancia_km - b.distancia_km);

    if (diffDistancia < 5) {
        return b.rating_count - a.rating_count; // Desempate por popularidade
    }

    return a.distancia_km - b.distancia_km; // Ordena por mais perto
});

// Pega apenas as Top 3 candidatas
const finalistas = rodoviariasGoogle.slice(0, 3);

// --- 6. RETORNO ---
const encontrouAlgo = finalistas.length > 0;

return [{
    json: {
        encontrado: encontrouAlgo,
        rodoviarias_locais: finalistas,
        // Mantemos estrutura similar ao aeroporto para facilitar pro Agente
        debug_excluidos: listaExcluidos,
        total_analisado: resultados.length,
        total_filtrado: rodoviariasGoogle.length
    }
}];

// ===============================
// 0. SANITIZAÇÃO
// ===============================
function sanitizeJsonString(str) {
  if (typeof str !== 'string') return str;
  return str.replace(/[\u0000-\u001F]+/g, '');
}

// ===============================
// 1. PARSE PROFUNDO ROBUSTO
// ===============================
function safeDeepParse(input, maxDepth = 10) {
  let current = input;

  for (let i = 0; i < maxDepth; i++) {

    // Se for string → tenta parse
    if (typeof current === 'string') {
      let cleaned = sanitizeJsonString(current).trim();

      try {
        current = JSON.parse(cleaned);
        continue;
      } catch {
        // Fallback: extrai JSON da string
        const match = cleaned.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
        if (match) {
          try {
            current = JSON.parse(match[0]);
            continue;
          } catch {}
        }

        return current;
      }
    }

    // Se tiver .query → desce nível
    if (current && typeof current === 'object' && current.query !== undefined) {
      current = current.query;
      continue;
    }

    break;
  }

  return current;
}

// ===============================
// 2. PREPARAÇÃO DOS DADOS
// ===============================
const jsonEntrada = items[0].json;

// 🔥 EXTRAÇÃO DIRETA (ANTI-JSON QUEBRADO)
let enderecoRaw = null;

if (typeof jsonEntrada.query === 'string') {
  const matchEndereco = jsonEntrada.query.match(/"endereco"\s*:\s*"([^"]+)"/i);
  if (matchEndereco) {
    enderecoRaw = matchEndereco[1];
  }
}

let dadosProcessados = {};

try {
  if (jsonEntrada.query !== undefined) {
    dadosProcessados = safeDeepParse(jsonEntrada.query);
  } else if (jsonEntrada.body !== undefined) {
    dadosProcessados = safeDeepParse(jsonEntrada.body);
  } else {
    dadosProcessados = safeDeepParse(jsonEntrada);
  }
} catch (e) {
  dadosProcessados = jsonEntrada;
}

// Garante objeto válido
if (typeof dadosProcessados !== 'object' || dadosProcessados === null) {
  dadosProcessados = {};
}

// ===============================
// 3. BUSCA FLEXÍVEL
// ===============================
function getValor(chave, obj) {
  if (!obj) return null;
  const chaveLower = chave.toLowerCase();

  for (let k in obj) {
    if (k.toLowerCase() === chaveLower) {
      return obj[k];
    }
  }

  return null;
}

// ===============================
// 4. NORMALIZAÇÃO DE TRANSPORTE
// ===============================
function normalizarTransporte(valor) {
  if (!valor) return "aereo";

  const texto = valor
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");

  if (texto.includes("aereo") || texto.includes("aviao") || texto.includes("voo") || texto.includes("aeroporto")) {
    return "aereo";
  }

  if (texto.includes("rodoviari") || texto.includes("onibus") || texto.includes("bus") || texto.includes("terminal")) {
    return "rodoviario";
  }

  if (texto.includes("transfer") || texto.includes("van") || texto.includes("shuttle")) {
    return "transfer";
  }

  if (
    texto.includes("carro") ||
    texto.includes("proprio") ||
    texto.includes("carona") ||
    texto.includes("taxi") ||
    texto.includes("uber") ||
    texto.includes("99") ||
    texto.includes("aplicativo")
  ) {
    return "outro";
  }

  return "aereo";
}

// ===============================
// 5. EXTRAÇÃO DOS DADOS
// ===============================
let endereco =
  enderecoRaw ||
  getValor('endereco', dadosProcessados) ||
  getValor('address', dadosProcessados);

let destino = getValor('destino', dadosProcessados);

let rawFlag = getValor('flag_internacional', dadosProcessados);
let flagInt = (rawFlag === true || rawFlag === 'true');

let excluidos =
  getValor('opcoes_excluidas', dadosProcessados) ||
  getValor('aeroportos_excluidos', dadosProcessados);

let rawTipo = getValor('tipo_transporte', dadosProcessados);
let tipoTransporte = rawTipo ? normalizarTransporte(rawTipo) : null;

let event_id = getValor('event_id', dadosProcessados);

// ===============================
// 6. FORMATAÇÃO DO DESTINO
// ===============================
let destinoFormatado = "Destino Indefinido";

if (destino) {
  try {
    const d = typeof destino === 'string'
      ? JSON.parse(sanitizeJsonString(destino))
      : destino;

    const cidade = Array.isArray(d.cities)
      ? d.cities[0]
      : (d.city || "");

    const pais = d.country || "";

    destinoFormatado = [cidade, pais].filter(Boolean).join(", ");
  } catch {
    destinoFormatado = destino.toString().trim();
  }
}

// ===============================
// 7. FALLBACK DE ENDEREÇO
// ===============================
if (!endereco) {
  const cidade = getValor('cidade', dadosProcessados);
  const estado = getValor('estado', dadosProcessados);

  if (cidade && estado) {
    endereco = `${cidade} - ${estado}`;
  }
}

// ===============================
// 8. VALIDAÇÃO
// ===============================
if (!endereco) {
  return [{
    json: {
      erro: "Endereço não encontrado.",
      debug_entrada: jsonEntrada,
      debug_processado: dadosProcessados
    }
  }];
}

if (!destino) destino = "Destino Indefinido";
if (!excluidos) excluidos = [];

// ===============================
// 9. NORMALIZA EXCLUÍDOS
// ===============================
if (typeof excluidos === 'string') {
  try {
    const clean = sanitizeJsonString(excluidos).trim();

    if (clean.startsWith('[')) {
      excluidos = JSON.parse(clean);
    } else {
      excluidos = clean
        .replace(/[\[\]"']/g, "")
        .split(',')
        .map(s => s.trim().toUpperCase())
        .filter(Boolean);
    }
  } catch {
    excluidos = [];
  }
}

// ===============================
// 10. RETORNO FINAL
// ===============================
return [{
  json: {
    endereco,
    destino,
    destino_formatado: destinoFormatado,
    flag_internacional: flagInt,
    aeroportos_excluidos: Array.isArray(excluidos) ? excluidos : [],
    tipo_transporte: tipoTransporte,
    event_id
  }
}];

