  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return parseFloat((R * c).toFixed(2));
}
function deg2rad(deg) { return deg * (Math.PI/180); }

// --- 2. RECUPERAÇÃO DOS NOMES ORIGINAIS ---
// IMPORTANTE: O nome dentro do $() deve ser IDÊNTICO ao nome do seu node no canvas.
// Você disse que o node se chama "Separa Endereços". Se for "Separar" (com R), ajuste abaixo.
