    // Tenta pegar a string original (Ex: "SUCURSAL SOROCABA - Rua X...")
    // O Google Maps (items) mantém a mesma ordem do input (dadosOriginais)
    let stringCompletaOriginal = "";
    if (dadosOriginais.length > i) {
        // Tenta pegar do campo endereco_para_geocoding ou meeting_points
        stringCompletaOriginal = dadosOriginais[i].json.endereco_para_geocoding || dadosOriginais[i].json.meeting_points;
    }

    if (googleResult) {
        const loc = googleResult.geometry.location;
        const dist = getDistanceFromLatLonInKm(userLat, userLng, loc.lat, loc.lng);

        // EXTRAÇÃO DO NOME (Lógica do Hífen)
        let nomeExtraido = "Transfer";

        if (stringCompletaOriginal && typeof stringCompletaOriginal === 'string') {
            if (stringCompletaOriginal.includes('-')) {
                // Pega tudo antes do primeiro hífen
                nomeExtraido = stringCompletaOriginal.split('-')[0].trim();
            } else {
                // Se não tem hífen, usa o início da string ou um padrão
                nomeExtraido = "Transfer (" + stringCompletaOriginal.substring(0, 10) + "...)";
            }
        } else {
            // Se falhou em pegar o original, usa o nome do Google (geralmente é o endereço)
            nomeExtraido = "Ponto de Encontro";
        }

        transfersCalculados.push({
            nome: nomeExtraido, 
            endereco: googleResult.formatted_address, // Endereço limpo do Google
            distancia_km: dist,
            tipo: "Transfer/Van",
            // DEBUG: Isso vai te mostrar de onde ele tentou tirar o nome
            _debug_origem: stringCompletaOriginal
        });
    }
}

// --- 4. ORDENAÇÃO E RETORNO ---
transfersCalculados.sort((a, b) => a.distancia_km - b.distancia_km);
const topTransfers = transfersCalculados.slice(0, 3);

return [{
    json: {
        encontrado: topTransfers.length > 0,
        transfers_locais: topTransfers,
        debug_total: transfersCalculados.length
    }
}];

const nodeDestino = $('Converter Destino em Latitude/Longitude2').first().json.results[0].geometry.location;
const destLat = nodeDestino.lat;
const destLng = nodeDestino.lng;

function getDistanceFromLatLonInKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = deg2rad(lat2 - lat1);
  const dLon = deg2rad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(deg2rad(lat1)) * Math.cos(deg2rad(lat2)) * Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return parseFloat((R * c).toFixed(2));
}
function deg2rad(deg) { return deg * (Math.PI/180); }

const palavrasProibidas = ["heliponto", "heliporto", "hangar", "aeroclube", "pista", "taxi", "táxi", "estacionamento"];

let resultados = items[0].json.results || [];

let aeroportosDestino = resultados.map(local => ({
  nome: local.name,
  endereco: local.vicinity || local.formatted_address,
  rating: local.user_ratings_total || 0,
  distancia_km: getDistanceFromLatLonInKm(destLat, destLng, local.geometry.location.lat, local.geometry.location.lng),
  place_id: local.place_id
}));

aeroportosDestino = aeroportosDestino.filter(a => {
  const nomeLower = a.nome.toLowerCase();
  if (palavrasProibidas.some(p => nomeLower.includes(p))) return false;
  if (a.rating < 50) return false;
  return true;
});

aeroportosDestino.sort((a, b) => a.distancia_km - b.distancia_km);

return [{ json: { aeroportos_destino: aeroportosDestino.slice(0, 3) } }];
